    44	uint32_t nfapi_calculate_checksum(uint8_t *buffer, uint16_t len) {
    45	  uint32_t chksum = 0;
    46	  // calcaulte upto the checksum
    47	  chksum = crc32(chksum, buffer, 8);
    48	  // skip the checksum
    49	  uint8_t zeros[4] = {0, 0, 0, 0};
    50	  chksum = crc32(chksum, zeros, 4);
    51	  // continu with the rest of the mesage
    52	  chksum = crc32(chksum, &buffer[NFAPI_P7_HEADER_LENGTH], len - NFAPI_P7_HEADER_LENGTH);
    53	  // return the inverse
    54	  return ~(chksum);
    55	}
